const EXAMS = [{"id": 1, "title": "Đề 1", "count": 10, "duration_minutes": 15, "questions": [{"id": 85, "q": "Phân loại theo lĩnh vực Hành chính nhà nước thì TTHC” Đăng ký xe từ điểm đăng ký xe khác chuyển đến” thuộc loại nào?", "options": {"A": "TTHC cấp xã thực hiện", "B": "Đăng ký, quản lý phương tiện giao thông mô tô và xe gắn máy", "C": "Đăng ký, quản lý phương tiện giao thông cơ giới, xe máy chuyên dùng", "D": "TTHC cấp tỉnh thực hiện"}, "correct": "C"}, {"id": 97, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây là quy định hành vi bị nghiêm cấm của cán bộ,công chức được phân công thực hiện TTHC", "options": {"A": "Tất cả các phương án trên", "B": "Tù chối thực hiện, kéo dài thời gian thực hiện hoặc tự ý yêu cầu bổ sung thêm hồ sơ, giấy tờ ngoài quy định mà không nêu rõ lý lo bằng văn bản", "C": "Hách dịch, cửa quyền,sách nhiễu, gây phiền hà, gây khó khăn cho đối tượng thực hiện TTHC", "D": "đùn đẩy trách nhiệm, thiếu hợp tác, chậm trễ, gây cản trở trong thực hiện nhiệm vụ được giao"}, "correct": "A"}, {"id": 66, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính", "B": "tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợi ích chính đáng của các tổ chức và cá nhân.", "C": "Kiểm soát TTHC có hiệu quả là hoạt động mang lại lợi ích trực  tiếp cho các cá nhân, tổ chức nhưng đồng thời không để sơ hở  trong công tác quản lý nhà nước. Thực tế đã chỉ ra rằng, nếu không làm tốt công tác giám sát, kiểm  soát TTHC thì các hoạt động nhằm cải cách thủ tục hành chính đôi  khi chỉ mang tính hình thức", "D": "là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật"}, "correct": "C"}, {"id": 41, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "B": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "C": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "D": "Hỗ trợ người có công, người cao tuổi, người tàn tật, người nghèo, phụ nữ mang thai, trẻ mồ côi và người thuộc diện bảo trợ xã hội khác trong thực hiện thủ tục hành chính."}, "correct": "D"}, {"id": 109, "q": "bản chính giấy tờ, văn bản trong phương án nào dưới đây được dùng làm cơ sở để chứng thực phản sao trong thủ tục” Chứng thực bản sao từ bản chính giấy tờ, văn bản do cơ quan tổ chức có thẩm quyền của VN cấp hoặc chứng nhận”?", "options": {"A": "bản chính giấy tờ, văn bản đóng dấu mật của cơ quan, tổ chức có thẩm quyền", "B": "Bản sao công chứng giấy chứng nhận quyền sử dụng đất", "C": "giấy khai sinh bản sao", "D": "Giấy khai sinh bản chính do cơ quan có thẩm quyền cấp"}, "correct": "A"}, {"id": 13, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Đơn giản, dễ hiểu và dễ thực hiện", "B": "Quy phạm có tính thủ tục để đưa pháp luật vào đời sống thực tế", "C": "Bảo đảm khách quan, công bằng trong thực hiện thủ tục hành chính", "D": "Linh hoạt theo yêu cầu triển khai pháp luật vào đời sống"}, "correct": "A"}, {"id": 73, "q": "Phân loại theo lĩnh vực  quản lý hành chính nhà nước thì thủ tục hành chính “ Đăng ký khai tử” thuộc lĩnh vực nào sau đây", "options": {"A": "Lĩnh vực quốc tịch", "B": "Lĩnh vực hội tịch", "C": "Lĩnh vực tư pháp", "D": "Lĩnh vực cư trú"}, "correct": "B"}, {"id": 54, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Hướng dẫn, giải thích, cung cấp thông tin chính xác, đầy đủ, kịp thời về thủ tục hành chính cho cá nhân, tổ chức có liên quan.", "B": "Từ chối thực hiện những yêu cầu không được quy định trong thủ tục hành chính hoặc chưa được công khai theo quy định", "C": "Thực hiện cơ chế một cửa, một cửa liên thông trong thực hiện thủ tục hành chính", "D": "Thực hiện nghiêm túc, đầy đủ nhiệm vụ được giao trong quá trình thực hiện thủ tục hành chính"}, "correct": "B"}, {"id": 49, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Hướng dẫn, giải thích, cung cấp thông tin chính xác, đầy đủ, kịp thời về thủ tục hành chính cho cá nhân, tổ chức có liên quan", "B": "Không tự đặt ra thủ tục hành chính, hồ sơ, giấy tờ ngoài quy định của pháp luật", "C": "Phối hợp và chia sẻ thông tin trong quá trình giải quyết công việc của cá nhân, tổ chức", "D": "Hướng dẫn tổ chức, cá nhân thực hiện trình tự, hồ sơ hành chính đầy đủ, rõ ràng, chính xác không để tổ chức, cá nhân phải đi lại bổ sung hồ sơ quá hai lần cho một vụ việc, trừ trường hợp tổ chức, cá nhân thực hiện không đúng theo hướng dẫn của cán bộ, công chức được phân công thực hiện thủ tục hành chính"}, "correct": "D"}, {"id": 11, "q": "Đâu là ý nghĩa của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính có sự linh hoạt theo yêu cầu triển khai pháp luật vào đời sống", "B": "Thủ tục hành chính có tính đa dạng, phức tạp", "C": "Thủ tục hành chính là quy phạm có tính thủ tục để đưa pháp luật vào đời sống thực tế", "D": "Thủ tục hành chính biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính"}, "correct": "D"}]}, {"id": 2, "title": "Đề 2", "count": 10, "duration_minutes": 15, "questions": [{"id": 47, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Cấp giấy biên nhận hồ sơ, tài liệu theo quy định.", "B": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính", "C": "Nêu rõ lý do bằng văn bản trong trường hợp từ chối thực hiện hoặc có yêu cầu bổ sung giấy tờ trong thời hạn giải quyết theo quy định", "D": "Sử dụng, bố trí cán bộ, công chức có phẩm chất đạo đức tốt, văn hóa giao tiếp chuẩn mực, đủ trình độ về chuyên môn, nghiệp vụ và năng lực phù hợp để thực hiện thủ tục hành chính"}, "correct": "B"}, {"id": 14, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Bảo đảm tính liên thông, kịp thời, chính xác, không gây phiền hà trong thực hiện thủ tục hành chính", "B": "Phù hợp với mục tiêu quản lý hành chính nhà nước", "C": "Được thực hiện một cách thống nhất", "D": "Linh hoạt theo yêu cầu triển khai pháp luật vào đời sống"}, "correct": "B"}, {"id": 74, "q": "Phương án nào dưới đây là đặc điểm của TTHC", "options": {"A": "TTHC có sự linh hoạt theo yêu cầu triển khai PL vào Đs", "B": "TTHC thể hiện mức độ văn minh của nền hành chính", "C": "TTHC được  thực hiện giải quyết công việc cho người dân", "D": "TTHC là quy phạm pháp luật đơn giản dễ hiểu, phù hợp với mục tiêu Qli"}, "correct": "A"}, {"id": 45, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước", "options": {"A": "Hướng dẫn tổ chức, cá nhân thực hiện trình tự, hồ sơ hành chính đầy đủ, rõ ràng, chính xác không để tổ chức, cá nhân phải đi lại bổ sung hồ sơ quá hai lần cho một vụ việc, trừ trường hợp tổ chức, cá nhân thực hiện không đúng theo hướng dẫn của cán bộ, công chức được phân công thực hiện thủ tục hành chính", "B": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "C": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "D": "Thực hiện quy định khác của pháp luật"}, "correct": "D"}, {"id": 65, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật", "B": "Việc kiểm soát TTHC để nâng cao chất lượng hệ thống các quy định hành chính.", "C": "tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợi ích chính đáng của các tổ chức và cá nhân.", "D": "biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính"}, "correct": "B"}, {"id": 53, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Thực hiện đầy đủ các quy định về thủ tục hành chính.", "B": "Sử dụng, bố trí cán bộ, công chức có phẩm chất đạo đức tốt, văn hóa giao tiếp chuẩn mực, đủ trình độ về chuyên môn, nghiệp vụ và năng lực phù hợp để thực hiện thủ tục hành chính", "C": "Không tự đặt ra thủ tục hành chính, hồ sơ, giấy tờ ngoài quy định của pháp luật", "D": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính"}, "correct": "A"}, {"id": 110, "q": "Phương án nào sau đây không phải nội dung đăng ký hộ tịch", "options": {"A": "XN vào sổ hộ tịch sự kiệp cấp căn cước công dân", "B": "XN vào sổ hộ tịch sự kiện giám hộ", "C": "---------------------------------------- sự kiện xác định lại dân tộc", "D": "Nhận cha mẹ con"}, "correct": "A"}, {"id": 9, "q": "Đâu là ý nghĩa của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính được thực hiện một cách thống nhất", "B": "Thủ tục hành chính bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "C": "Thủ tục hành chính có tính đa dạng, phức tạp", "D": "Thủ tục hành chính do cơ quan nhà nước, người có thẩm quyền quy định"}, "correct": "B"}, {"id": 86, "q": "Theo quy định của pháp luật hiện hành, Bộ phận một cửa cấp xã do cơ quan hay cá nhân quyết định thành lập", "options": {"A": "Chủ tịch ubnd cấp tỉnh", "B": "Chủ tịch ubnd xã", "C": "UBND cấp tỉnh", "D": "UBND cấp xã"}, "correct": "D"}, {"id": 98, "q": "23. Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung, phương án nào dưới đây là nguyên tắc tiếp nhận, xử lý phản ánh kiến nghị của cá nhân tổ chức về quy định hành chính", "options": {"A": "Hợp tình, hợp lý", "B": "Nhanh chóng, khách quan", "C": "công khai minh bạc", "D": "Công bằng, ngắn gọn"}, "correct": "B"}]}, {"id": 3, "title": "Đề 3", "count": 10, "duration_minutes": 15, "questions": [{"id": 99, "q": "23. Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung” tiếp nhận và giải quyết hồ sơ cá nhân, tổ chức theo quy định” là trách nhiệm của cơ quan hay cá nhân nào dưới đây", "options": {"A": "Cơ quan thực hiện TTHC", "B": "Cán bộ, công chức quy định TTHC", "C": "Cán bộ, cc được phân công thực hiện TTHC", "D": "Chủ tịch Ubnd cấp xã"}, "correct": "C"}, {"id": 16, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Bảo đảm khách quan, công bằng trong thực hiện thủ tục hành chính", "B": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "C": "Bảo đảm quyền bình đẳng của các đối tượng thực hiện thủ tục hành chính", "D": "Bảo đảm công khai, minh bạch các thủ tục hành chính đang được"}, "correct": "C"}, {"id": 87, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi, bổ sung phương án nào dưới đây là nguyên tắc thực hiện TTHC?", "options": {"A": "Đảm bảo tính hợp hiến, hợp pháp, của các quy định về TTHC", "B": "Bảo đảm tính liên thông, kịp thời, không gây phiền hà trong thực hiện TTHC", "C": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước", "D": "Đơn giản, dễ hiểu và thực hiện"}, "correct": "B"}, {"id": 51, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính", "B": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "C": "Thực hiện cơ chế một cửa, một cửa liên thông trong thực hiện thủ tục hành chính", "D": "Bảo quản và giữ bí mật về hồ sơ tài liệu và các thông tin liên quan đến bí mật cá nhân trong quá trình giải quyết theo quy định của pháp luật, trừ trường hợp phải thu thập, công bố thông tin, tư liệu theo quyết định của cơ quan, tổ chức nhà nước có thẩm quyền"}, "correct": "B"}, {"id": 37, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "B": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "C": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính.", "D": "Bảo quản và giữ bí mật về hồ sơ tài liệu và các thông tin liên quan đến bí mật cá nhân trong quá trình giải quyết theo quy định của pháp luật, trừ trường hợp phải thu thập, công bố thông tin, tư liệu theo quyết định của cơ quan, tổ chức nhà nước có thẩm quyền"}, "correct": "D"}, {"id": 75, "q": "TTHC nào dưới đây được phân loại theo ngành lĩnh vực quản lý hành chính nhà nước", "options": {"A": "TTHC địa phương", "B": "TTHC trung ương", "C": "TTHC về cư trú", "D": "TTHC liên hệ"}, "correct": "B"}, {"id": 59, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "B": "Sử dụng, bố trí cán bộ, công chức có phẩm chất đạo đức tốt, văn hóa giao tiếp chuẩn mực, đủ trình độ về chuyên môn, nghiệp vụ và năng lực phù hợp để thực hiện thủ tục hành chính", "C": "Khiếu nại, tố cáo, khởi kiện các quyết định hành chính và hành vi hành chính theo quy định của pháp luật", "D": "Bảo quản và giữ bí mật về hồ sơ tài liệu và các thông tin liên quan đến bí mật cá nhân trong quá trình giải quyết theo quy định của pháp luật, trừ trường hợp phải thu thập, công bố thông tin, tư liệu theo quyết định của cơ quan, tổ chức nhà nước có thẩm quyền"}, "correct": "C"}, {"id": 111, "q": "Phương án nào dưới đây là trường hợp không được miễn lệ phí khi thực hiện thủ tục” đăng ký khai sinh”( cho công dân VN cư trú ở trong nước)", "options": {"A": "thuộc hộ nghèo", "B": "Gia đình có công với cách mạng", "C": "không đúng hạn", "D": "Đúng hạn"}, "correct": "C"}, {"id": 2, "q": "Đâu là đặc điểm của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "B": "Thủ tục hành chính là quy phạm có tính thủ tục để đưa pháp luật vào đời sống thực tế", "C": "Thủ tục hành chính bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "D": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện"}, "correct": "B"}, {"id": 71, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "B": "biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính", "C": "là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật", "D": "Bổ sung thủ tục hành chính cần thiết, đáp ứng nhu cầu thực tế;"}, "correct": "D"}]}, {"id": 4, "title": "Đề 4", "count": 10, "duration_minutes": 15, "questions": [{"id": 100, "q": "Theo quy định của Pháp luật hiện hành, căn cứ số lượng TTHC thuộc thẩm quyền giải quyết, tần suất tiếp nhận hồ sơ và tình hình bố trí trụ sở Bộ phận tiếp nhận và trả kết quả tại bộ, cơ quan ngang bộ do cơ quan hay cá nhân nào quyết định thành lập", "options": {"A": "bộ, cơ quan ngang bộ", "B": "Thủ tướng chính phủ", "C": "Chính phủ", "D": "Bộ trưởng, Thủ trưởng cơ quan ngang bộ"}, "correct": "D"}, {"id": 68, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "Kiểm soát thủ tục hành chính đáp ứng yêu cầu công khai, minh bạch trong quá trình tổ chức thực hiện thủ tục hành chính.", "B": "bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "C": "bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "D": "tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợi ích chính đáng của các tổ chức và cá nhân."}, "correct": "A"}, {"id": 18, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "B": "Bảo đảm khách quan, công bằng trong thực hiện thủ tục hành chính", "C": "Bảo đảm tính liên thông, kịp thời, chính xác, không gây phiền hà trong thực hiện thủ tục hành chính", "D": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước"}, "correct": "D"}, {"id": 76, "q": "PL theo quan hệ công tác thì TTHC “ Cấp lại giấy phép lao động nước ngoài làm việc tại Việt nam” thuộc loại nào dưới đây", "options": {"A": "TTHC nội bộ", "B": "TTHC Cấp tỉnh thực hiện", "C": "TTHC cấp xã thực hiện", "D": "TTHC liên hệ"}, "correct": "D"}, {"id": 44, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước", "options": {"A": "Hướng dẫn tổ chức, cá nhân thực hiện trình tự, hồ sơ hành chính đầy đủ, rõ ràng, chính xác không để tổ chức, cá nhân phải đi lại bổ sung hồ sơ quá hai lần cho một vụ việc, trừ trường hợp tổ chức, cá nhân thực hiện không đúng theo hướng dẫn của cán bộ, công chức được phân công thực hiện thủ tục hành chính", "B": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "C": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính", "D": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố"}, "correct": "C"}, {"id": 28, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Đối tượng giải quyết", "B": "Chủ thể thực hiện", "C": "Cơ quan giải quyết thủ tục hành chính", "D": "Nơi nhận"}, "correct": "C"}, {"id": 50, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "B": "Bảo quản và giữ bí mật về hồ sơ tài liệu và các thông tin liên quan đến bí mật cá nhân trong quá trình giải quyết theo quy định của pháp luật, trừ trường hợp phải thu thập, công bố thông tin, tư liệu theo quyết định của cơ quan, tổ chức nhà nước có thẩm quyền", "C": "Không tự đặt ra thủ tục hành chính, hồ sơ, giấy tờ ngoài quy định của pháp luật", "D": "Hướng dẫn, giải thích, cung cấp thông tin chính xác, đầy đủ, kịp thời về thủ tục hành chính cho cá nhân, tổ chức có liên quan"}, "correct": "A"}, {"id": 88, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây là nguyên tắc thực hiện TTHC?", "options": {"A": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "B": "Tiết kiệm thời gian  và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước", "C": "phù hợp với mục tiêu ql", "D": "Đảm bảo tính đồng bộ, hiệu quả của các quy định về TTHC"}, "correct": "A"}, {"id": 112, "q": "Phương án nào dưới đây là 1 trong các giấy tờ cần nộp để thực hiện thủ tục “ chứng thực bản sao từ bản chính giấy tờ, văn bản do cơ quan tổ chức có thẩm quyền của VN cấp hoặc chứng nhận”", "options": {"A": "căn cước công dân đã được cơ quan có thẩm quyền chứng thực", "B": "Bản chính giấy tờ, văn bản do cơ quan tổ chức có thẩm quyền của Vn cấp hoặc chứng nhận", "C": "Giấy tờ chứng minh nơi cư trú để xác định cơ quan có thẩm quyền thực hiện", "D": "Văn bản đồng ý cho thực hiện chứng thực của người có thẩm quyền."}, "correct": "B"}, {"id": 5, "q": "Đâu là đặc điểm của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "B": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "C": "Thủ tục hành chính biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính", "D": "Thủ tục hành chính có tính đa dạng, phức tạp"}, "correct": "D"}]}, {"id": 5, "title": "Đề 5", "count": 9, "duration_minutes": 15, "questions": [{"id": 89, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung cá nhân hay cơ quan nào dưới đây không có thẩm quyền công bố TTHC", "options": {"A": "UBND cấp xã", "B": "Chủ tịch UBND tỉnh, thành phố trực thuộc trung ương", "C": "Bộ trưởng, Thủ trưởng cơ quan ngang bộ", "D": "Người đứng đầu cơ quan, đơn vị được cơ quan nhà nước cấp trên giao nhiệm vụ hoặc ủy quyền ban hành văn bản hướng dẫn thực hiện thủ tục giải quyết công việc cho cá nhân, tổ chứ"}, "correct": "A"}, {"id": 46, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Thực hiện nghiêm túc, đầy đủ nhiệm vụ được giao trong quá trình thực hiện thủ tục hành chính", "B": "Nêu rõ lý do bằng văn bản trong trường hợp từ chối thực hiện hoặc có yêu cầu bổ sung giấy tờ trong thời hạn giải quyết theo quy định", "C": "Cấp giấy biên nhận hồ sơ, tài liệu theo quy định.", "D": "Sử dụng, bố trí cán bộ, công chức có phẩm chất đạo đức tốt, văn hóa giao tiếp chuẩn mực, đủ trình độ về chuyên môn, nghiệp vụ và năng lực phù hợp để thực hiện thủ tục hành chính"}, "correct": "A"}, {"id": 101, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây không phải là nội dung rà soát, đánh giá TTHC", "options": {"A": "Các nguyên tắc quy định  TTHC theo quy định pháp luật", "B": "Các nguyên tắc thực hiện TTHC theo quy định Pl", "C": "Sự đầy đủ số lượng văn bản TTHC", "D": "Tính hợp pháp của TTHC, quy định có liên quan đến TTHC"}, "correct": "C"}, {"id": 27, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Nội dung thủ tục", "B": "Đối tượng thực hiện thủ tục hành chính", "C": "Cơ quan thực hiện thủ tục", "D": "Chủ thể thực hiện thủ tục"}, "correct": "B"}, {"id": 63, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "Kiểm soát thủ tục hành chính góp phần xây dựng nền hành chính chuyên nghiệp, hiệu quả và hiện đại.", "B": "tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợi ích chính đáng của các tổ chức và cá nhân.", "C": "là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật", "D": "biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính"}, "correct": "A"}, {"id": 77, "q": "PL dựa trên quan hệ công tác của cơ quan hành chính nhà nước thì TTHC” Cấp phiếu lý lịch tư pháp cho công dân VN, người nước ngoài đang cư trú tại Việt Nam” thuộc loại TTHC nào trong các Phương án", "options": {"A": "TTHC công an xã", "B": "TTHC của Sở Tư Pháp", "C": "TTHC nội bộ", "D": "TTHC liên hệ"}, "correct": "B"}, {"id": 3, "q": "Đặc điểm nào sau đây là đặc điểm của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "B": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "C": "Thủ tục hành chính do cơ quan nhà nước, người có thẩm quyền quy định", "D": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện"}, "correct": "C"}, {"id": 42, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Thực hiện cơ chế một cửa, một cửa liên thông trong thực hiện thủ tục hành chính", "B": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "C": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "D": "Tiếp nhận và giải quyết hồ sơ của cá nhân, tổ chức theo quy định."}, "correct": "A"}, {"id": 17, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Bảo đảm quyền được phản ánh, kiến nghị của các cá nhân, tổ chức đối với các thủ tục hành chính", "B": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "C": "Bảo đảm quyền bình đẳng của các đối tượng thực hiện thủ tục hành chính", "D": "Bảo đảm công khai, minh bạch các thủ tục hành chính đang được"}, "correct": "C"}]}, {"id": 6, "title": "Đề 6", "count": 9, "duration_minutes": 15, "questions": [{"id": 102, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây là trách nhiệm của cán bộ, công chức được phân công thực hiện TTHC", "options": {"A": "Hỗ trợ người có công, người cao tuổi, người tàn tật,người nghèo, yêu phụ nữ mang thai, trẻ mồ côi, và người thuộc diện bảo trợ xã hội khác trong thực hiện TTHC", "B": "Chịu trách nhiệm công bố, tổ chức nhập dữ liệu về TTHC đã công bố trên cơ sở dữ liệu quốc gia về TTHC theo quy định", "C": "Chịu trách nhiệm về tính hợp pháp, chính xác của các giấy tờ có trong hồ sơ và cung cấp đầy đủ thông tin có liên quan.", "D": "Chấp hành nhiêm túc các quy định của cấp có thẩm quyền về TTHC đã được người đứng đầu Bộ ,cơ quan ngang bộ, UBND tỉnh, thành phố trực thuộc Trung ương công bố"}, "correct": "D"}, {"id": 78, "q": "PL theo lĩnh vực quản lý hành chính nhà nước TTHC” thông báo lưu trú” thuộc lĩnh vực", "options": {"A": "Lĩnh vực lưu trú", "B": "Lĩnh vực đăng kí, quản lý lưu trú", "C": "Lĩnh vực lý lịch tư pháp", "D": "Lĩnh vực hộ tịch"}, "correct": "A"}, {"id": 30, "q": "Nguyên tắc nào sau đây là nguyên tắc thực hiện thủ tục hành chính?", "options": {"A": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước", "B": "Bảo đảm khách quan, công bằng trong thực hiện thủ tục hành chính", "C": "Đảm bảo tính hợp hiến, hợp pháp, thống nhất, đồng bộ, hiệu quả của các quy định về thủ tục hành chính", "D": "Phù hợp với mục tiêu quản lý hành chính nhà nước"}, "correct": "B"}, {"id": 90, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây không thuộc nội dung rà soát, đánh giá thủ tục hành chính?", "options": {"A": "Tính hợp pháp của TTHC", "B": "Sự ngắn gọn của TTHC", "C": "Chí phí tuân thủ của TTHC", "D": "Sự cần thiết của TTHC"}, "correct": "B"}, {"id": 21, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Bảo đảm khách quan, công bằng trong thực hiện thủ tục hành chính", "B": "Đảm bảo tính hợp hiến, hợp pháp, thống nhất, đồng bộ, hiệu quả của các quy định về thủ tục hành chính", "C": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "D": "Bảo đảm công khai, minh bạch các thủ tục hành chính đang được"}, "correct": "B"}, {"id": 70, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "B": "là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật", "C": "Kịp thời phát hiện để loại bỏ hoặc chỉnh sửa thủ tục hành chính không phù hợp, phức tạp, phiền hà;", "D": "biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính"}, "correct": "C"}, {"id": 25, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Chủ thể giải quyết hồ sơ", "B": "Đối tượng giải quyết hồ sơ", "C": "Nơi nhận", "D": "Thành phần, số lượng hồ sơ"}, "correct": "D"}, {"id": 38, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Nêu rõ lý do bằng văn bản trong trường hợp từ chối thực hiện hoặc có yêu cầu bổ sung giấy tờ trong thời hạn giải quyết theo quy định", "B": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "C": "Tiếp nhận và giải quyết hồ sơ của cá nhân, tổ chức theo quy định.", "D": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi"}, "correct": "A"}, {"id": 4, "q": "Đặc điểm nào sau đây là đặc điểm của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính được thực hiện một cách thống nhất", "B": "Thủ tục hành chính biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính", "C": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "D": "Thủ tục hành chính bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất"}, "correct": "A"}]}, {"id": 7, "title": "Đề 7", "count": 9, "duration_minutes": 15, "questions": [{"id": 43, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Hướng dẫn tổ chức, cá nhân thực hiện trình tự, hồ sơ hành chính đầy đủ, rõ ràng, chính xác không để tổ chức, cá nhân phải đi lại bổ sung hồ sơ quá hai lần cho một vụ việc, trừ trường hợp tổ chức, cá nhân thực hiện không đúng theo hướng dẫn của cán bộ, công chức được phân công thực hiện thủ tục hành chính", "B": "Tiếp nhận, xử lý các phản ánh, kiến nghị của cá nhân, tổ chức trong thực hiện thủ tục hành chính", "C": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "D": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi"}, "correct": "B"}, {"id": 72, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "Bảo đảm quy định thủ tục hành chính đơn giản, dễ hiểu, dễ thực hiện, tiết kiệm thời gian, chi phí, công sức của đối tượng và cơ quan thực hiện thủ tục hành chính.", "B": "biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính", "C": "là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật", "D": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện"}, "correct": "A"}, {"id": 91, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung “ Thực hiện nghiêm túc, đầy đủ nhiệm vụ được giao trong quá trình thực hiện TTHC” là trách nhiệm của cơ quan hay cá nhân?", "options": {"A": "Chủ tịch ubnd các cấp", "B": "Cơ quan thực hiện TTHC", "C": "cán bộ, công chức quy định TTHC", "D": "Cán bộ,cc được phân công thực hiện TTH"}, "correct": "D"}, {"id": 103, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây không phải là bộ phận tạo thành cơ bản của 1 TTHC", "options": {"A": "Đối tượng thực hiện TTHC", "B": "Lĩnh vực TTHC", "C": "Thành phần, số lượng hồ sơ", "D": "Cơ quan giải quyết TTHC"}, "correct": "B"}, {"id": 79, "q": "PL theo lĩnh vực quản lý hành chính nhà nước thì TTHC “ Cấp giấy chứng nhận đăng ký tàu cá” thuộc lv", "options": {"A": "Lĩnh vực thủy sản", "B": "Lĩnh vực dk Doanh nghiệp", "C": "Lĩnh vực doanh nghiệp", "D": "Lĩnh vực ql tàu cá"}, "correct": "A"}, {"id": 61, "q": "Đâu là khái niệm kiểm soát thủ tục hành chính?", "options": {"A": "Kiểm soát thủ tục hành chính được hiểu là việc xem xét, đánh giá, theo dõi nhằm bảo đảm tính khả thi của quy định về thủ tục hành chính, đáp ứng yêu cầu công khai, minh bạch trong quá trình tổ chức thực hiện thủ tục hành chính.", "B": "Kiểm soát thủ tục hành chính được hiểu là Giám sát việc thực hiện thủ tục hành chính; phản ánh, kiến nghị với cơ quan nhà nước, người có thẩm quyền về những bất hợp lý của thủ tục hành chính và các hành vi vi phạm của cán bộ, công chức trong thực hiện thủ tục hành chính", "C": "Kiểm soát thủ tục hành chính được hiểu là Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "D": "Kiểm soát thủ tục hành chính được hiểu là các quy phạm thủ tục của nhà nước về cách thức tiến hành các hoạt động quản lý hành chính nên chúng tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợ ích chính đáng của các tổ chức và cá nhân"}, "correct": "A"}, {"id": 19, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "B": "Bảo đảm công khai, minh bạch các thủ tục hành chính đang được", "C": "Bảo đảm quyền được phản ánh, kiến nghị của các cá nhân, tổ chức đối với các thủ tục hành chính", "D": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước"}, "correct": "D"}, {"id": 32, "q": "Nguyên tắc nào sau đây là nguyên tắc thực hiện thủ tục hành chính?", "options": {"A": "Đảm bảo tính hợp hiến, hợp pháp, thống nhất, đồng bộ, hiệu quả của các quy định về thủ tục hành chính", "B": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước", "C": "Phù hợp với mục tiêu quản lý hành chính nhà nước", "D": "Bảo đảm quyền được phản ánh, kiến nghị của các cá nhân, tổ chức đối với các thủ tục hành chính"}, "correct": "D"}, {"id": 24, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Thành phần thực hiện", "B": "Cách thức giải quyết thủ tục hành chính", "C": "Cách thức thực hiện", "D": "Chủ thể thực hiện thủ tục"}, "correct": "C"}]}, {"id": 8, "title": "Đề 8", "count": 9, "duration_minutes": 15, "questions": [{"id": 62, "q": "Đâu là khái niệm kiểm soát thủ tục hành chính?", "options": {"A": "Kiểm soát thủ tục hành chính được hiểu là việc xem xét, đánh giá, theo dõi nhằm bảo đảm tính khả thi của quy định về thủ tục hành chính", "B": "Kiểm soát thủ tục hành chính được hiểu là đáp ứng yêu cầu công khai, minh bạch", "C": "Kiểm soát thủ tục hành chính được hiểu là trong quá trình tổ chức thực hiện thủ tục hành chính.", "D": "tất cả a,b,c"}, "correct": "D"}, {"id": 104, "q": "Trường hợp nào dưới đây không được miễn lệ phí khi thực hiện thủ tục” đăng kí khai tử” cho công dân Việt nam", "options": {"A": "TH dki khai tử không đúng hạn", "B": "Th người khuyết tất", "C": "TH người thuộc hộ nghèo", "D": "TH người thuộc gd có công cm"}, "correct": "A"}, {"id": 35, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "B": "Hướng dẫn, giải thích, cung cấp thông tin chính xác, đầy đủ, kịp thời về thủ tục hành chính cho cá nhân, tổ chức có liên quan.", "C": "Tiếp nhận và giải quyết hồ sơ của cá nhân, tổ chức theo quy định.", "D": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính."}, "correct": "B"}, {"id": 92, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây không là nội dung rà soát, đánh giá thủ tục hành chính", "options": {"A": "Sự cần thiết của TTHC", "B": "Sự ngắn gọn của TTHC", "C": "Tính hợp lý của TTHC", "D": "Tính hợp pháp của TTHC"}, "correct": "B"}, {"id": 31, "q": "Nguyên tắc nào sau đây là nguyên tắc thực hiện thủ tục hành chính?", "options": {"A": ". Đảm bảo tính hợp hiến, hợp pháp, thống nhất, đồng bộ, hiệu quả của các quy định về thủ tục hành chính", "B": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước", "C": "Bảo đảm tính liên thông, kịp thời, chính xác, không gây phiền hà trong thực hiện thủ tục hành chính", "D": "Phù hợp với mục tiêu quản lý hành chính nhà nước"}, "correct": "C"}, {"id": 80, "q": "Phương án nào dưới đây không phải là tiêu chí phân loại TTHC", "options": {"A": "Dựa trên quan hệ công tác của cơ quan hành chính nhà nước", "B": "Theo lĩnh vực quản lý hành chính nhà nước", "C": "Theo chủ thể quy định TTHC", "D": "Theo phân cấp ql hành chính nhà nước"}, "correct": "C"}, {"id": 22, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Tên thủ tục hành chính", "B": "Nơi nhận", "C": "Thủ trưởng cơ quan, đơn vị", "D": "Chủ thể thực hiện thủ tục hành chính"}, "correct": "A"}, {"id": 57, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Không hối lộ hoặc dùng các thủ đoạn khác để lừa dối cơ quan nhà nước, người có thẩm quyền trong thực hiện thủ tục hành chính", "B": "Hướng dẫn, giải thích, cung cấp thông tin chính xác, đầy đủ, kịp thời về thủ tục hành chính cho cá nhân, tổ chức có liên quan.", "C": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính", "D": "Hướng dẫn tổ chức, cá nhân thực hiện trình tự, hồ sơ hành chính đầy đủ, rõ ràng, chính xác không để tổ chức, cá nhân phải đi lại bổ sung hồ sơ quá hai lần cho một vụ việc, trừ trường hợp tổ chức, cá nhân thực hiện không đúng theo hướng dẫn của cán bộ, công chức được phân công thực hiện thủ tục hành chính"}, "correct": "A"}, {"id": 12, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Đơn giản, dễ hiểu và dễ thực hiện", "B": "Bảo đảm công khai, minh bạch các thủ tục hành chính đang được", "C": "Do cơ quan nhà nước, người có thẩm quyền quy định", "D": "Linh hoạt theo yêu cầu triển khai pháp luật vào đời sống"}, "correct": "A"}]}, {"id": 9, "title": "Đề 9", "count": 9, "duration_minutes": 15, "questions": [{"id": 15, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Bảo đảm tính liên thông, kịp thời, chính xác, không gây phiền hà trong thực hiện thủ tục hành chính", "B": "Phù hợp với mục tiêu quản lý hành chính nhà nước", "C": "Bảo đảm quyền được phản ánh, kiến nghị của các cá nhân, tổ chức đối với các thủ tục hành chính", "D": "Được thực hiện một cách thống nhất"}, "correct": "B"}, {"id": 93, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây là nguyên tắc kiểm soát TTHC", "options": {"A": "Kiểm soát TTHC công bằng, khách quan", "B": "Kiểm soát TTHC phải đảm bảo dúng đối tượng", "C": "Kiểm soát TTHC phải đảm bảo công khai, minh bạch", "D": "Kiểm soát TTHC phải đảm bảo thực hiện có hiệu quả mục tiêu CCHC, bảo đảm điều phối, huy động sự tham gia tích cực, rộng rãi của tất cả các cơ quan tổ chức, cá nhân vào quá trình kiểm soát TTHC"}, "correct": "D"}, {"id": 34, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Sử dụng, bố trí cán bộ, công chức có phẩm chất đạo đức tốt, văn hóa giao tiếp chuẩn mực, đủ trình độ về chuyên môn, nghiệp vụ và năng lực phù hợp để thực hiện thủ tục hành chính", "B": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính", "C": "Tiếp nhận và giải quyết hồ sơ của cá nhân, tổ chức theo quy định.", "D": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính"}, "correct": "A"}, {"id": 81, "q": "PL theo lĩnh vực quản lý hành chính nhà nước thì TTHC “ Cấp phiếu lý lịch tư pháp cho công dân VN, người nước ngoài đang cư trú tại VN”", "options": {"A": "Lĩnh vực hộ tịch", "B": "Lĩnh vực lý lịch tư pháp", "C": "Lĩnh vực Quốc tịch", "D": "Lĩnh vực dk, quản lý cư trú"}, "correct": "B"}, {"id": 55, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính", "B": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính", "C": "Chịu trách nhiệm về tính hợp pháp, chính xác của các giấy tờ có trong hồ sơ và cung cấp đầy đủ thông tin có liên quan", "D": "Cấp giấy biên nhận hồ sơ, tài liệu theo quy định."}, "correct": "C"}, {"id": 26, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Thời hạn giải quyết", "B": "Trình tự giải quyết hồ sơ", "C": "Chủ thể giải quyết thủ tục", "D": "Nơi nhận"}, "correct": "A"}, {"id": 1, "q": "Khái niệm thủ tục hành chính theo nghị định 63 là ?", "options": {"A": "Thủ tục hành chính là trình tự, cách thức thực hiện, hồ sơ, yêu cầu, điều kiện do cơ quan nhà nước, người có thẩm quyền quy định để giải quyết một công việc cụ thể liên quan đến cá nhân, tổ chức.", "B": "Thủ tục hành chính là “trình tự, cách thức giải quyết công việc của cơ quan hành chính nhà nước có thẩm quyền trong mối quan hệ nội bộ hành chính và mối quan hệ giữa cơ quan hành chính nhà nước với tổ chức công dân”.", "C": "Thủ tục hành chính là một loại quy phạm pháp luật quy định, trình tự, cách thức giải quyết công việc của các cơ quan nhà nước có thẩm quyền trong mối quan hệ nội bộ hành chính và mối quan hệ giữa các cơ quan nhà nước với các tổ chức và cá nhân công dân.", "D": "TTHC là trình tự, cách thức giải quyết công việc của các cơ quan nhà nước có thẩm quyền trong mối quan hệ giữa các cơ quan nhà nước với các tổ chức và cá nhân công dân mà cả trong mối quan hệ nội bộ hành chính phát sinh trong hoạt động quản lý hành chính nhà nước."}, "correct": "A"}, {"id": 29, "q": "Nguyên tắc nào sau đây là nguyên tắc thực hiện thủ tục hành chính?", "options": {"A": "Bảo đảm công khai, minh bạch các thủ tục hành chính đang được", "B": "Bảo đảm quyền bình đẳng của các đối tượng thực hiện thủ tục hành chính", "C": "Đảm bảo tính hợp hiến, hợp pháp, thống nhất, đồng bộ, hiệu quả của các quy định về thủ tục hành chính", "D": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước"}, "correct": "A"}, {"id": 105, "q": "Phương án nào dưới đây là kết quả thực hiện thủ tục “ Thi tuyển công chức”", "options": {"A": "tb kết quả thi tuyển công chức", "B": "Giấy chứng nhận trình độ chuyên môn công chức", "C": "quyết định phê duyệt kết quả", "D": "Quyết định tuyển dụng công chức"}, "correct": "D"}]}, {"id": 10, "title": "Đề 10", "count": 9, "duration_minutes": 15, "questions": [{"id": 94, "q": "cơ quan hay cá nhân nào dưới đây có thẩm quyền quy định TTHC", "options": {"A": "Chính phủ", "B": "Chủ tịch UBND cấp tỉnh", "C": "Chủ tịch ubnd cấp xã", "D": "Bộ và cơ quan ngang bộ"}, "correct": "D"}, {"id": 23, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Chủ thể thực hiện thủ tục hành chính", "B": "Trình tự thực hiện", "C": "Quy trình thực hiện", "D": "Nơi nhận"}, "correct": "B"}, {"id": 33, "q": "Nguyên tắc nào sau đây là nguyên tắc thực hiện thủ tục hành chính?", "options": {"A": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "B": "Phù hợp với mục tiêu quản lý hành chính nhà nước", "C": "Đơn giản, dễ hiểu và dễ thực hiện", "D": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước"}, "correct": "A"}, {"id": 40, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "B": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "C": "Phối hợp và chia sẻ thông tin trong quá trình giải quyết công việc của cá nhân, tổ chức", "D": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính."}, "correct": "C"}, {"id": 6, "q": "Theo nghị định 63 đâu là đặc điểm của thủ tục hành chính ?", "options": {"A": "Thủ tục hành chính bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "B": "Thủ tục hành chính có sự linh hoạt theo yêu cầu triển khai pháp luật vào đời sống", "C": "Thủ tục hành chính biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính", "D": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện"}, "correct": "B"}, {"id": 82, "q": "Phương án nào dưới đây là tiêu chí phân loại TTHC", "options": {"A": "Dựa trên quan hệ công tác của cơ quan hành chính nhà nước", "B": "Theo sự xắp xếp của nhà nước", "C": "Theo chủ thể quy định TTHC", "D": "Theo đề nghị, yêu cầu của người dân"}, "correct": "A"}, {"id": 106, "q": "Phương án nào dưới đây không thuộc điều kiện thực hiện “ tt dk kết hôn”", "options": {"A": "nam nữ khác dân tộc kết hôn", "B": "Do nam và nữ tự nguyện", "C": "nam đủ 20 t, nữ 18t", "D": "Các bên không bị mất năng lực hành vi nhân sự"}, "correct": "A"}, {"id": 56, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Tiếp nhận và giải quyết hồ sơ của cá nhân, tổ chức theo quy định", "B": "Tiếp nhận, xử lý các phản ánh, kiến nghị của cá nhân, tổ chức trong thực hiện thủ tục hành chính", "C": "Nêu rõ lý do bằng văn bản trong trường hợp từ chối thực hiện hoặc có yêu cầu bổ sung giấy tờ trong thời hạn giải quyết theo quy định.", "D": "Không được cản trở hoạt động thực hiện thủ tục hành chính của cơ quan nhà nước, người có thẩm quyền"}, "correct": "D"}, {"id": 20, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "B": "Đảm bảo tính hợp hiến, hợp pháp, thống nhất, đồng bộ, hiệu quả của các quy định về thủ tục hành chính", "C": "Bảo đảm quyền được phản ánh, kiến nghị của các cá nhân, tổ chức đối với các thủ tục hành chính", "D": "Bảo đảm khách quan, công bằng trong thực hiện thủ tục hành chính"}, "correct": "B"}]}, {"id": 11, "title": "Đề 11", "count": 9, "duration_minutes": 15, "questions": [{"id": 83, "q": "Theo nghị định 63/2010/ND- CP của Chính phủ đã được  sửa đổi ,bổ sung, phương án nào dưới đây là trách nhiệm của cơ quan thực hiện TTHC", "options": {"A": "Thực hiện sự công tâm trong  giải quyết TTHC", "B": "Bảo đảm TTHC ngắn gọn, hợp lý", "C": "Bảo đảm TTHC đơn giản dễ hiểu", "D": "Nêu rõ lý do bằng văn bản trong trường hợp từ chối thực hiện hoặc có yêu cầu bổ sung giấy tờ trong thời hạn giải quyết theo quy định"}, "correct": "D"}, {"id": 7, "q": "Đặc điểm của thủ tục hành chính là?", "options": {"A": "Thủ tục hành chính có sự linh hoạt theo yêu cầu triển khai pháp luật vào đời sống,Thủ tục hành chính có tính đa dạng, phức tạp.", "B": "Thủ tục hành chính được thực hiện một cách thống nhất,Thủ tục hành chính do cơ quan nhà nước, người có thẩm quyền quy định.", "C": "Thủ tục hành chính là quy phạm có tính thủ tục để đưa pháp luật vào đời sống thực tế.", "D": "Tất cả đáp án trên"}, "correct": "D"}, {"id": 95, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây là nội dung trong một quyết định công bố TTHC mới ban hành", "options": {"A": "Thời gian thực hiện TTHC", "B": "Địa điểm TTHC", "C": "Các bộ phận tạo thành TTHC theo quy định", "D": "Không gian thực hiện TTHC"}, "correct": "A"}, {"id": 58, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính", "B": "Giám sát việc thực hiện thủ tục hành chính; phản ánh, kiến nghị với cơ quan nhà nước, người có thẩm quyền về những bất hợp lý của thủ tục hành chính và các hành vi vi phạm của cán bộ, công chức trong thực hiện thủ tục hành chính", "C": "Hỗ trợ người có công, người cao tuổi, người tàn tật, người nghèo, phụ nữ mang thai, trẻ mồ côi và người thuộc diện bảo trợ xã hội khác trong thực hiện thủ tục hành chính", "D": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố"}, "correct": "B"}, {"id": 48, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Sử dụng, bố trí cán bộ, công chức có phẩm chất đạo đức tốt, văn hóa giao tiếp chuẩn mực, đủ trình độ về chuyên môn, nghiệp vụ và năng lực phù hợp để thực hiện thủ tục hành chính", "B": "Phối hợp và chia sẻ thông tin trong quá trình giải quyết công việc của cá nhân, tổ chức", "C": "Tiếp nhận và giải quyết hồ sơ của cá nhân, tổ chức theo quy định.", "D": "Cấp giấy biên nhận hồ sơ, tài liệu theo quy định."}, "correct": "C"}, {"id": 67, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợi ích chính đáng của các tổ chức và cá nhân.", "B": "bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "C": "bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "D": "Công tác kiểm soát thủ tục hành chính góp phần tháo gỡ những  khó khăn, vướng mắc trong quá trình thực thi công vụ của cán bộ, công chức, giảm phiền hà cho nhân dân."}, "correct": "D"}, {"id": 36, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "B": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "C": "Cấp giấy biên nhận hồ sơ, tài liệu theo quy định", "D": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi"}, "correct": "C"}, {"id": 107, "q": "Đăng ký sự kiện hộ tịch khai sinh cho công dân VN cư trú ở trong nước thuộc thẩm quyền của cơ quan nào trong các phương án dưới đây?", "options": {"A": "Chủ tịch ubnd xã", "B": "Ubnd xã", "C": "Sở Tư pháp", "D": "UBND cấp tỉnh"}, "correct": "B"}, {"id": 8, "q": "Đâu là ý nghĩa của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "B": "Thủ tục hành chính được thực hiện một cách thống nhất", "C": "Thủ tục hành chính là quy phạm có tính thủ tục để đưa pháp luật vào đời sống thực tế", "D": "Thủ tục hành chính do cơ quan nhà nước, người có thẩm quyền quy định"}, "correct": "A"}]}, {"id": 12, "title": "Đề 12", "count": 9, "duration_minutes": 15, "questions": [{"id": 96, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung , nguyên tắc “ Đơn giản dễ hiểu và thực hiện” thuộc nguyên tắc nào dưới đây?", "options": {"A": "NT rà soát, đánh giá TTHC", "B": "NT quy định TTHC", "C": "NT kiểm soát TTHC", "D": "NT thực hiện TTHC"}, "correct": "B"}, {"id": 108, "q": "Phương án nào dưới đây là đối tượng thực hiện thủ tục “ dk kết hôn có yếu tố nước ngoài”", "options": {"A": "người VN định cư ở nước ngoài, người nước ngoài sinh sống tại Vn", "B": "Người nước ngoài sinh sống tại VN", "C": "Công dân vn, người Việt Nam định cư ở nước ngoài", "D": "Cá nhân, tổ chức"}, "correct": "A"}, {"id": 69, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "B": "Kiểm soát thủ tục hành chính có ý nghĩa lớn trong việc nâng cao chất lượng thủ tục hành chính được xây dựng và ban hành.", "C": "bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "D": "tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợi ích chính đáng của các tổ chức và cá nhân."}, "correct": "B"}, {"id": 84, "q": "Theo nghị định 63/2010/ND- CP của Chính phủ đã được  sửa đổi ,bổ sung,” tiếp nhận, xử lý các phản ánh, kiến nghị của cá nhân ,tổ chức trong thực hiện TTHC là trách nhiệm của cơ quan hay cá nhân", "options": {"A": "cơ quan quy định  TTHC", "B": "Cán bộ, công chức được phân công thực hiện TTHC", "C": "Cơ quan thực hiện TTHC", "D": "Người đứng đầu bộ, cơ quan ngang bộ, UBND tỉnh, thành phố trực thuộc Trung ương"}, "correct": "C"}, {"id": 10, "q": "Đâu là ý nghĩa của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính do cơ quan nhà nước, người có thẩm quyền quy định", "B": "Thủ tục hành chính là quy phạm có tính thủ tục để đưa pháp luật vào đời sống thực tế", "C": "Thủ tục hành chính là là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật", "D": "Thủ tục hành chính có sự linh hoạt theo yêu cầu triển khai pháp luật vào đời sống"}, "correct": "C"}, {"id": 64, "q": "Nguyên tắc kiểm soát thủ tục hành chính là?", "options": {"A": "Kiểm soát thủ tục hành chính phải bảo đảm thực hiện có hiệu quả mục tiêu cải cách thủ tục hành chính", "B": "cải cách hành chính; bảo đảm điều phối, huy động sự tham gia tích cực, rộng rãi", "C": "của tất cả các cơ quan, tổ chức, cá nhân vào quá trình kiểm soát thủ tục hành chính\"", "D": "cả a,b,c"}, "correct": "D"}, {"id": 52, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Thực hiện cơ chế một cửa, một cửa liên thông trong thực hiện thủ tục hành chính", "B": "Tiếp nhận, xử lý các phản ánh, kiến nghị của cá nhân, tổ chức trong thực hiện thủ tục hành chính", "C": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "D": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính"}, "correct": "C"}, {"id": 39, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "B": "Không tự đặt ra thủ tục hành chính, hồ sơ, giấy tờ ngoài quy định của pháp luật", "C": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "D": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính."}, "correct": "D"}, {"id": 60, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Thực hiện cơ chế một cửa, một cửa liên thông trong thực hiện thủ tục hành chính", "B": "Nêu rõ lý do bằng văn bản trong trường hợp từ chối thực hiện hoặc có yêu cầu bổ sung giấy tờ trong thời hạn giải quyết theo quy định", "C": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "D": "Trực tiếp hoặc uỷ quyền cho người đại diện hợp pháp của mình tham gia thực hiện thủ tục hành chính theo quy định của pháp luật"}, "correct": "D"}]}];